// RESILIENT INPUT PREP (v6.1 - OPUS)
const inputData = $input.item.json;
const executionId = $execution.id;

// GLOBAL REACH-BACK
const sourceNode = $('ValidateInput').item.json;

const propertySource = inputData['Property Source'] || sourceNode['Property Source'];
const zillowUrl = inputData['Zillow URL'] || sourceNode['Zillow URL'];
const address = inputData['Property Address'] || sourceNode['Property Address'];
const email = inputData['Email'] || sourceNode['Email'] || 'shai@superseller.agency';

let apifyInput = {};

if (propertySource === 'Zillow URL' && zillowUrl) {
    // DETAIL SCRAPER SCHEMA (Strict)
    apifyInput = {
        "startUrls": [{ "url": zillowUrl }],
        "maxImages": 10
    };
} else if (propertySource === 'Property Address' && address) {
    // SEARCH FALLBACK SCHEMA
    apifyInput = {
        "searchStringsArray": [address],
        "maxCrawledPlacesPerSearch": 1,
        "maxImages": 10
    };
} else {
    throw new Error(`CRITICAL: No valid property identity found. Source: ${propertySource}, URL: ${zillowUrl}, Addr: ${address}`);
}

const staticData = $getWorkflowStaticData('global');
if (!staticData[executionId]) {
    staticData[executionId] = {
        startTime: new Date().toISOString(),
        videoUrls: [],
        retryCount: 0
    };
}
staticData[executionId].email = email;
staticData[executionId].address = address || zillowUrl || 'Property';

return [{
    ...inputData,
    apifyInput,
    email,
    executionId,
    propertyIdentifier: address || zillowUrl || 'Property'
}];

