// Enterprise-grade property style extraction with defensive error handling
const executionId = $execution.id;
const staticData = $getWorkflowStaticData('global');

// Defensive access to Gemini response
let text = '';
try {
  const geminiNode = $('GeminiFloorPlanAnalysis').item;
  text = geminiNode?.json?.content?.parts?.[0]?.text || geminiNode?.json?.text || '';
} catch (e) {
  console.warn('Could not access Gemini response:', e.message);
  text = '';
}

let style = 'Cinematic';
let keyFeature = 'Luxury Property';
let estimatedSqft = 'Unknown';
let roomCount = 'Multiple';

if (text) {
  try {
    // Extract JSON from Gemini response
    const jsonMatch = text.match(/```json\n?([\s\S]*?)\n?```/) || [null, text];
    const jsonString = jsonMatch[1] || text;

    // Try to parse JSON
    const data = JSON.parse(jsonString);

    if (data && data.property_summary) {
      style = data.property_summary.style || 'Cinematic';
      keyFeature = data.property_summary.visual_key_feature || 'Luxury Property';
      estimatedSqft = data.property_summary.estimated_sqft || 'Unknown';
      roomCount = data.property_summary.room_count || 'Multiple';
    }
  } catch (e) {
    console.log('Gemini JSON parsing failed, using defaults:', e.message);
  }
}

// Enhanced static data for enterprise tracking
if (!staticData[executionId]) {
  staticData[executionId] = {};
}

staticData[executionId].propertyStyle = style;
staticData[executionId].keyFeature = keyFeature;
staticData[executionId].estimatedSqft = estimatedSqft;
staticData[executionId].roomCount = roomCount;
staticData[executionId].styleProcessedAt = new Date().toISOString();

// Return enhanced property data for downstream processing
return $input.all().map(item => ({
  json: {
    ...item.json,
    propertyStyle: style,
    keyFeature: keyFeature,
    estimatedSqft: estimatedSqft,
    roomCount: roomCount
  }
}));

// Enterprise-grade Claude response parsing with defensive error handling
const text = $input.item?.json?.content?.[0]?.text || $input.item?.json?.text || '';
const executionId = $execution.id;

let data;
try {
  // Multiple parsing strategies for robustness
  const jsonMatch = text.match(/```json\n?([\s\S]*?)\n?```/) || [null, text.trim()];
  const jsonText = jsonMatch[1] || text;

  // Clean common formatting issues
  const cleanedJson = jsonText
    .replace(/^[^{]*/, '') // Remove text before first {
    .replace(/[^}]*$/, '') // Remove text after last }
    .replace(/\n\s*\/\/.*$/gm, ''); // Remove line comments

  data = JSON.parse(cleanedJson);
} catch (e) {
  // Fallback parsing attempt
  try {
    const fallbackMatch = text.match(/\{[\s\S]*\}/);
    if (fallbackMatch) {
      data = JSON.parse(fallbackMatch[0]);
    } else {
      throw new Error('No valid JSON found in Claude response: ' + e.message);
    }
  } catch (fallbackError) {
    throw new Error('Failed to parse Claude JSON: ' + fallbackError.message);
  }
}

// Validate and normalize shot data
const rawShots = Array.isArray(data) ? data : (data.shots || data.shot_list || []);

if (!Array.isArray(rawShots) || rawShots.length === 0) {
  throw new Error('No valid shots found in Claude response.');
}

// Get realtor mode status - defensive access
let hasRealtorImage = false;
try {
  const convertNode = $('old').item;
  hasRealtorImage = convertNode?.json?.realtorBase64Data ? true : false;
} catch (e) {
  console.warn('Could not determine realtor mode, defaulting to false');
  hasRealtorImage = false;
}

// Enterprise shot validation and normalization
const shots = rawShots.slice(0, 6).map((shot, idx) => {
  if (!shot || typeof shot !== 'object') {
    console.warn('Shot ' + (idx + 1) + ' is invalid, using defaults');
    shot = {};
  }

  // Determine realtor mode for this specific shot
  const isRealtorShot = hasRealtorImage && (idx === 1 || idx === 3 || idx === 5);

  return {
    prompt_subject: shot.prompt_subject || shot.subject || 'Property Interior View ' + (idx + 1),
    prompt_lighting: shot.prompt_lighting || shot.lighting || 'Natural window light streaming through',
    prompt_camera: shot.prompt_camera || shot.movement || 'Slow dolly in',
    prompt_effect: shot.prompt_effect || shot.effect || '8K resolution, professional real estate cinematography',
    negative_prompt: shot.negative_prompt || 'people, humans, figures, blur, distortion, text, logos',
    imageUrl: shot.imageUrl || shot.image_url || '',
    realtorMode: shot.realtorMode !== undefined ? shot.realtorMode : isRealtorShot,
    shotOrder: idx + 1,
    executionId: executionId,
    generatedAt: new Date().toISOString()
  };
});

// Ensure exactly 6 shots
while (shots.length < 6) {
  const idx = shots.length;
  const isRealtorShot = hasRealtorImage && (idx === 1 || idx === 3 || idx === 5);

  shots.push({
    prompt_subject: 'Property Overview Shot ' + (shots.length + 1),
    prompt_lighting: 'Natural daylight',
    prompt_camera: 'Fixed lens, locked off camera',
    prompt_effect: '8K resolution, professional real estate cinematography',
    negative_prompt: 'people, humans, figures, blur, distortion, text, logos',
    imageUrl: '',
    realtorMode: isRealtorShot,
    shotOrder: shots.length + 1,
    executionId: executionId,
    generatedAt: new Date().toISOString()
  });
}

// Log shot generation for monitoring
console.log('Generated ' + shots.length + ' shots for execution ' + executionId);

// Return normalized shots
return shots.map(shot => ({ json: shot }));

